from collections import defaultdict

class RetrievalAnalytics:
    def __init__(self):
        self.log = defaultdict(list)

    def record(self, lang: str, score: float):
        self.log[lang].append(score)

    def summary(self) -> dict:
        return {
            lang: {
                "count": len(scores),
                "avg_score": round(sum(scores) / len(scores), 3),
            }
            for lang, scores in self.log.items()
        }

analytics = RetrievalAnalytics()
analytics.record("eu", 0.91)
analytics.record("eu", 0.87)
analytics.record("ja", 0.74)
print(analytics.summary())
